def get_recommendation(user_id, movie_id):
    # Get the ratings data of the users
    user_ratings = df_ratings[df_ratings['userId'] == user_id]
    # Get the ratings data of other users for the same movie
    other_ratings = df_ratings[(df_ratings['user_id'] != user_id) & (df_ratings['movieId'] == movie_id)]
    # Join the data
    combined_data = pd.concat([user_ratings, other_ratings], axis=0);
    # Pivot the data so that the rows represent users and the columns to movies
    pivoted_data = combined_data.pivot_table(index='userId', columns='movieId', values='rating').fill(0);
    # Train the K Nearest Neighbors model
    knn_model = KNeighborsClassifier(n_neighbors=5);
    knn_model.fit(pivoted_data.values,pivoted_data.index);
    # Predict the recommendation for given movie and user
    user_row = pivoted_data.loc[user_id].values.reshape(1, -1);
    predicted_rating = knn_model.predict(user_row);
