```
public class PlagiarismDetector {
    public static double detectPlagiarism(String text1, String text2) {
        String[] words1 = text1.split("\\s+");
        String[] words2 = text2.split("\\s+");
        Map<String, Integer> wordCount1 = new HashMap<>();
        Map<String, Integer> wordCount2 = new HashMap<>();
        for (String word : words1) {
            wordCount1.put(word, wordCount1.getOrDefault(word, 0) + 1);
        }
        for (String word : words2) {
            wordCount2.put(word, wordCount2.getOrDefault(word, 0) + 1);
        }
        int commonWords = 0;
        for (String word : wordCount1.keySet()) {
            if (wordCount2.containsKey(word)) {
                commonWords += Math.min(wordCount1.get(word), wordCount2.get(word));
            }
        }
        return (double) commonWords / (words1.length + words2.length - commonWords);
    }
}
