const sha256 = require('sha256');
const { Worker } = require('worker_threads');

async function bruteForceSHA256(targetHash, maxLength) {
  const alphabet = 'abcdefghijklmnopqrstuvwxyz';
  const alphabetLen = alphabet.length;
  const numWorkers = require('os').cpus().length;
  const workerResults = new Array(numWorkers);
  let result = null;

  let tasks = [];
  let taskId = 0;

  for (let i = 0; i < numWorkers; i++) {
    tasks.push([]);
  }

  const workerFunction = (taskId) => {
    async function workerBacktrack(currentString) {
      if (sha256(currentString) === targetHash) {
        return currentString;
      }

      if (currentString.length >= maxLength) {
        return null;
      }

      for (let i = 0; i < alphabetLen; i++) {
        const result = await workerBacktrack(currentString + alphabet[i]);
        if (result) {
          return result;
        }
      }

      return null;
    }

    const taskQueue = tasks[taskId];
    while (taskQueue.length) {
      const { str, depth } = taskQueue.pop();
      const tempResult = await workerBacktrack(str);
      if (tempResult) {
        result = tempResult;
        break;
      }
    }

    return result;
  };

  const promises = [];

  for (let i = 0; i < numWorkers && !result; i++) {
    const taskQueue = tasks[i];
    for (let j = 0; j < maxLength / numWorkers; j++) {
      taskQueue.push({ str: '', depth: 0 });
    }
    const worker = new Worker(workerFunction.toString(), { eval: true });
    promises.push(
      new Promise((resolve) => {
        worker.on('message', (data) => {
          workerResults[taskId] = data;
          resolve();
        });
        worker.postMessage(i);
      })
    );
    taskId++;
  }

  await Promise.all(promises);

  for (const res of workerResults) {
    if (res) {
      result = res;
      break;
    }
  }

  return result;
}

